    public void addAssetOnboardedData(String username, String vdmsid, JSONObject asset_data) {
        String docker_name = asset_data.getString("docker_name");
        String location_id = asset_data.getString("location_id");
        JSONArray temp_asset_ids = JSON.parseArray(asset_data.getJSONArray("temp_asset_ids").toJSONString());
        List<DeviceDTO> deviceDTOList = new ArrayList<>();
        try {
            JSONArray final_asset_data = apiCallService.getTemporaryProductByIds(temp_asset_ids);
            if (final_asset_data.size() > 0) {
                for (int i = 0; i < final_asset_data.size(); i++) {
                    JSONObject asset_data_object = final_asset_data.getJSONObject(i);
                    List<SpecificationsDTO> specifications = this.updateDeviceSpecificationDetails(JSON.parseArray(asset_data_object.getString("specifications")));
                    DeviceDTO deviceDTO = new DeviceDTO();
                    deviceDTO.setDocker_name(docker_name);
                    if (location_id == null) {
                        location_id = asset_data_object.getString("location_id");
                        int count = locationService.getLocationId(location_id);
                        if (count == 0) {
                            location_id = null;
                        }
                    }
                    deviceDTO.setLocation_id(location_id);
                    deviceDTO.setModel(asset_data_object.getString("model"));
                    deviceDTO.setVendor(asset_data_object.getString("vendor"));
                    deviceDTO.setVirtual_device_type(2);
                    deviceDTO.setDescription(asset_data_object.getString("description"));
                    deviceDTO.setSpecifications(specifications);
                    deviceDTO.setAsset_group("generic");
                    deviceDTO.setAsset_image_url(asset_data_object.getString("image_url"));
                    deviceDTO.setUser_data_name(asset_data_object.getString("name"));
                    deviceDTO.setMonitor(1);
                    deviceDTOList.add(deviceDTO);
                }
            }
        } catch (Exception e) {
            System.out.println(e);
        }
        if (deviceDTOList.size() > 0) {
            ExecutorService executorService = Executors.newSingleThreadExecutor();
            executorService.execute(() -> {
                deviceService.addAssetOnboardedDevices(username, vdmsid, deviceDTOList);
                apiCallService.deleteTemporaryProductByIds(temp_asset_ids);
            });
            executorService.shutdown();
        }
    }

    public List<SpecificationsDTO> updateDeviceSpecificationDetails(JSONArray specifications) {
        List<SpecificationsDTO> final_specifications = new ArrayList<>();
        try {
            if (specifications.size() > 0) {
                for (int i = 0; i < specifications.size(); i++) {
                    JSONObject specification_object = specifications.getJSONObject(i);
                    SpecificationsDTO specificationsDTO = new SpecificationsDTO();
                    specificationsDTO.setKey_name(specification_object.getString("key"));
                    specificationsDTO.setKey_value(specification_object.getString("value"));
                    final_specifications.add(specificationsDTO);
                }
            }
        } catch (Exception e) {
            System.out.println(e);
        }
        return final_specifications;
    }

    public void assetUpsert(DeviceDTO device, String vdmsid, String assetImportType, String username) {
        assetRepository.assetUpsert(device.getId(), device.getUser_data_name(), device.getDescription(), device.getType(), null, null, null, null, 7, null, null, "", device.getCustom_fields(), null, false, null, vdmsid, 0, assetImportType);
//        deviceService.updateVirtualDeviceOnboardStatusByAssetMapper(device,username);
    }

